# shapes.spy - Base definitions for geometric shapes
# Exports: Shape (abstract class), IDrawable (interface), Color (enum)

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    color: Color

    def __init__(self, color: Color):
        self.color = color

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return "A shape"

    @virtual
    def get_color_name(self) -> str:
        return self.color.name

