# geometry.spy - Concrete shape implementations
# Imports from shapes and implements concrete classes
from shapes import Shape, IDrawable, Color

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

class Rectangle(Shape, IDrawable):
    width: float
    height: float
    top_left: Point

    def __init__(self, width: float, height: float, top_left: Point, color: Color):
        super().__init__(color)
        self.width = width
        self.height = height
        self.top_left = top_left

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle: " + str(self.width) + " x " + str(self.height)

    @override
    def draw(self) -> str:
        return "Drawing rectangle at (" + str(self.top_left.x) + ", " + str(self.top_left.y) + ")"

class Circle(Shape, IDrawable):
    radius: float
    center: Point

    def __init__(self, radius: float, center: Point, color: Color):
        super().__init__(color)
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return "Circle: radius=" + str(self.radius)

    @override
    def draw(self) -> str:
        return "Drawing circle centered at (" + str(self.center.x) + ", " + str(self.center.y) + ")"

