# shape_utils.spy - Utility functions for shape operations
from shapes import Shape, IDrawable, Color
from geometry import Rectangle, Circle, Point

def create_default_rect() -> Rectangle:
    origin: Point = Point(0.0, 0.0)
    return Rectangle(10.0, 5.0, origin, Color.BLUE)

def create_default_circle() -> Circle:
    origin: Point = Point(5.0, 5.0)
    return Circle(3.0, origin, Color.RED)

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total

def paint_description(drawable: IDrawable) -> str:
    return drawable.draw()

def get_shape_info(shape: Shape) -> str:
    return shape.describe() + " with area " + str(shape.area())
